<div class="message-input">
    <textarea @bind="Text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="1"></textarea>
    <button @onclick="Submit" disabled="@string.IsNullOrWhiteSpace(Text)">@ButtonText</button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message...";
    [Parameter] public string ButtonText { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSubmit { get; set; }

    private string Text { get; set; } = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Submit();
        }
    }

    private async Task Submit()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var content = Text.Trim();
        Text = "";
        await OnSubmit.InvokeAsync(content);
    }
}
"}

