toolArgs.file_text:
@using sv_053a5689a8a8426fa07e4ede3d2ccdfc.Services

<div class="message-item @(_showActions ? "hovered" : "")"
     @onmouseenter="() => _showActions = true"
     @onmouseleave="OnMouseLeave">
    <div class="message-avatar">@Message.Author[..1].ToUpper()</div>
    <div class="message-body">
        <div class="message-header">
            <span class="message-author">@Message.Author</span>
            <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
        </div>
        <div class="message-content">@Message.Content</div>

        @if (Message.Reactions.Count > 0)
        {
            <div class="message-reactions">
                @foreach (var reaction in Message.Reactions)
                {
                    <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                        @reaction.Emoji @reaction.Users.Count
                    </span>
                }
            </div>
        }

        @if (ShowThreadActions && ThreadInfo is not null)
        {
            <button class="thread-link" @onclick="() => OnReplyClick.InvokeAsync()">
                💬 @ThreadInfo.ReplyCount @(ThreadInfo.ReplyCount == 1 ? "reply" : "replies")
            </button>
        }
    </div>

    @if (_showActions && ShowThreadActions)
    {
        <div class="message-actions">
            <button class="action-btn" title="Reply in thread" @onclick="() => OnReplyClick.InvokeAsync()">
                💬
            </button>
            <button class="action-btn" title="Add reaction"
                    @onclick="ToggleEmojiPicker"
                    @onclick:stopPropagation="true">
                😀
            </button>
        </div>
    }

    @if (_showEmojiPicker)
    {
        <div class="emoji-picker-container">
            <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public ThreadSummary? ThreadInfo { get; set; }
    [Parameter] public bool ShowThreadActions { get; set; } = true;
    [Parameter] public EventCallback OnReplyClick { get; set; }
    [Parameter] public EventCallback<string> OnReactClick { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private void OnMouseLeave()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnReactClick.InvokeAsync(emoji);
    }

    internal static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        return diff switch
        {
            { TotalSeconds: < 60 } => "just now",
            { TotalMinutes: < 60 } => $"{(int)diff.TotalMinutes} min ago",
            { TotalHours: < 24 } => $"{(int)diff.TotalHours}h ago",
            { TotalDays: < 7 } => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

