.message-item {
    display: flex;
    gap: 12px;
    padding: 6px 16px;
    position: relative;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item.hovered {
    background: #2e3035;
}

.message-avatar {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    background: #5865f2;
    color: white;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
    font-size: 0.85rem;
    flex-shrink: 0;
    margin-top: 2px;
}

.message-body {
    flex: 1;
    min-width: 0;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    font-size: 0.9rem;
    color: #f2f3f5;
}

.message-time {
    font-size: 0.72rem;
    color: #949ba4;
}

.message-content {
    font-size: 0.9rem;
    color: #dbdee1;
    line-height: 1.45;
    word-wrap: break-word;
}

.message-reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: #2b2d31;
    border: 1px solid #3f4147;
    border-radius: 6px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: default;
    color: #dbdee1;
}

.reaction-badge:hover {
    border-color: #5865f2;
}

.thread-link {
    background: none;
    border: none;
    color: #00a8fc;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0;
    font-weight: 500;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #2f3136;
    border: 1px solid #3f4147;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.25);
    z-index: 5;
}

.action-btn {
    background: none;
    border: none;
    font-size: 1rem;
    padding: 4px 8px;
    border-radius: 4px;
    cursor: pointer;
    line-height: 1;
}

.action-btn:hover {
    background: #40444b;
}

.emoji-picker-container {
    position: absolute;
    right: 16px;
    top: -48px;
    z-index: 20;
}

