@using sv_053a5689a8a8426fa07e4ede3d2ccdfc.Services

<div class="channel-item @(IsActive ? "active" : "") @(Channel.UnreadCount > 0 ? "has-unread" : "")"
     @onclick="OnClick">
    <div class="channel-info">
        <div class="channel-name"><span class="hash">#</span> @Channel.Name</div>
        @if (!string.IsNullOrEmpty(Channel.Description))
        {
            <div class="channel-description">@TruncateDescription(Channel.Description)</div>
        }
    </div>
    @if (Channel.UnreadCount > 0)
    {
        <span class="unread-badge">@Channel.UnreadCount</span>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }

    private static string TruncateDescription(string description)
        => description.Length > 30 ? description[..30] + "…" : description;
}

