export function initialize(messageList, dotNetRef) {
    if (!messageList) return null;

    let loading = false;

    const onScroll = () => {
        if (!loading && messageList.scrollTop < 50) {
            loading = true;
            dotNetRef.invokeMethodAsync('OnScrollNearTop').then(() => {
                loading = false;
            });
        }
    };

    messageList.addEventListener('scroll', onScroll);

    // Scroll to bottom on first load
    messageList.scrollTop = messageList.scrollHeight;

    return { messageList, onScroll };
}

export function scrollToBottom(messageList) {
    if (messageList) {
        messageList.scrollTop = messageList.scrollHeight;
    }
}

export function getScrollHeight(messageList) {
    return messageList ? messageList.scrollHeight : 0;
}

export function restoreScrollPosition(messageList, previousScrollHeight) {
    if (messageList) {
        messageList.scrollTop = messageList.scrollHeight - previousScrollHeight;
    }
}

export function dispose(state) {
    if (state?.messageList && state?.onScroll) {
        state.messageList.removeEventListener('scroll', state.onScroll);
    }
}

@using sv_053a5689a8a8426fa07e4ede3d2ccdfc.Services
@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="message-area">
    <div class="message-area-header">
        <h2><span class="header-hash">#</span> @CurrentChannel?.Name</h2>
        @if (!string.IsNullOrEmpty(CurrentChannel?.Description))
        {
            <p class="header-description">@CurrentChannel.Description</p>
        }
    </div>

    <div class="message-list" @ref="_messageListRef">
        @if (IsLoadingMore)
        {
            <div class="load-more-indicator">Loading older messages…</div>
        }
        else if (HasMoreMessages)
        {
            <div class="load-more-indicator">Scroll up for more</div>
        }

        @foreach (var message in Messages.Where(m => m.ReplyToId is null))
        {
            <MessageItem Message="message"
                         ThreadInfo="GetThreadInfo(message.Id)"
                         OnReplyClick="() => OnOpenThread.InvokeAsync(message.Id)"
                         OnReactClick="(emoji) => HandleReact(message.Id, emoji)" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{CurrentChannel?.Name}")"
                  ButtonText="Send"
                  OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter] public Channel? CurrentChannel { get; set; }
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool HasMoreMessages { get; set; }
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<ReactionRequest> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference _messageListRef;
    private IJSObjectReference? _module;
    private IJSObjectReference? _scrollState;
    private DotNetObjectReference<MessageArea>? _dotNetRef;
    private bool _initialized;

    private ThreadSummary? GetThreadInfo(int messageId)
        => ThreadSummaries.GetValueOrDefault(messageId);

    private async Task HandleReact(int messageId, string emoji)
        => await OnReact.InvokeAsync(new ReactionRequest(messageId, emoji));

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/Chat/MessageArea.razor.js");
            _dotNetRef = DotNetObjectReference.Create(this);
            _scrollState = await _module.InvokeAsync<IJSObjectReference>(
                "initialize", _messageListRef, _dotNetRef);
            _initialized = true;
        }
    }

    [JSInvokable]
    public async Task OnScrollNearTop()
    {
        if (!IsLoadingMore && HasMoreMessages)
        {
            await OnLoadMore.InvokeAsync();
        }
    }

    public async Task ScrollToBottomAsync()
    {
        if (_module is not null && _initialized)
        {
            await _module.InvokeVoidAsync("scrollToBottom", _messageListRef);
        }
    }

    public async Task PreserveScrollAsync(double previousScrollHeight)
    {
        if (_module is not null && _initialized)
        {
            await _module.InvokeVoidAsync("restoreScrollPosition", _messageListRef, previousScrollHeight);
        }
    }

    public async Task<double> GetScrollHeightAsync()
    {
        if (_module is not null && _initialized)
        {
            return await _module.InvokeAsync<double>("getScrollHeight", _messageListRef);
        }
        return 0;
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                if (_scrollState is not null)
                {
                    await _module.InvokeVoidAsync("dispose", _scrollState);
                    await _scrollState.DisposeAsync();
                }
            }
            catch (JSDisconnectedException) { }
            await _module.DisposeAsync();
        }
        _dotNetRef?.Dispose();
    }
}

