@using sv_053a5689a8a8426fa07e4ede3d2ccdfc.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    <div class="thread-root">
        <div class="thread-root-author">@RootMessage.Author</div>
        <div class="thread-root-content">@RootMessage.Content</div>
        <div class="thread-root-time">@MessageItem.FormatRelativeTime(RootMessage.SentAt)</div>
    </div>

    <div class="thread-divider">
        <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
    </div>

    <div class="thread-replies">
        @foreach (var reply in Replies)
        {
            <MessageItem Message="reply" ShowThreadActions="false" />
        }
    </div>

    <MessageInput Placeholder="Reply…" ButtonText="Reply" OnSubmit="OnSendReply" />
</div>

@code {
    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
}

.thread-panel {
    width: 350px;
    min-width: 350px;
    background: #2b2d31;
    border-left: 1px solid #1e1f22;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #3f4147;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #f2f3f5;
}

.close-btn {
    background: none;
    border: none;
    color: #949ba4;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    line-height: 1;
}

.close-btn:hover {
    background: #3f4147;
    color: #f2f3f5;
}

.thread-root {
    padding: 12px 16px;
    border-bottom: 1px solid #3f4147;
    flex-shrink: 0;
}

.thread-root-author {
    font-weight: 600;
    font-size: 0.88rem;
    color: #f2f3f5;
    margin-bottom: 4px;
}

.thread-root-content {
    font-size: 0.88rem;
    color: #dbdee1;
    line-height: 1.4;
}

.thread-root-time {
    font-size: 0.72rem;
    color: #949ba4;
    margin-top: 4px;
}

.thread-divider {
    padding: 8px 16px;
    flex-shrink: 0;
}

.thread-divider span {
    font-size: 0.72rem;
    font-weight: 600;
    color: #949ba4;
    text-transform: uppercase;
    letter-spacing: 0.03em;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

