@page "/chat"
@rendermode InteractiveServer
@using sv_053a5689a8a8426fa07e4ede3d2ccdfc.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <ChannelList Channels="_channels"
                 SelectedChannelId="_selectedChannel?.Id"
                 OnChannelSelected="SelectChannel" />

    <MessageArea @ref="_messageArea"
                 CurrentChannel="_selectedChannel"
                 Messages="_messages"
                 ThreadSummaries="_threadSummaries"
                 HasMoreMessages="_hasMoreMessages"
                 IsLoadingMore="_isLoadingMore"
                 OnSendMessage="SendMessage"
                 OnOpenThread="OpenThread"
                 OnReact="HandleReaction"
                 OnLoadMore="LoadMoreMessages" />

    @if (_threadOpen && _threadRootMessage is not null)
    {
        <ThreadPanel RootMessage="_threadRootMessage"
                     Replies="_threadReplies"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> _channels = [];
    private Channel? _selectedChannel;
    private List<Message> _messages = [];
    private Dictionary<int, ThreadSummary> _threadSummaries = new();
    private bool _hasMoreMessages = true;
    private bool _isLoadingMore;
    private int _skip;

    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message> _threadReplies = [];

    private MessageArea? _messageArea;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        _selectedChannel = channel;
        _skip = 0;
        _hasMoreMessages = true;
        _messages = [];
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];

        var messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = messages;
        _skip = messages.Count;
        _hasMoreMessages = messages.Count >= PageSize;

        BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Clear unread badge
        var idx = _channels.FindIndex(c => c.Id == channel.Id);
        if (idx >= 0)
        {
            _channels[idx] = channel with { UnreadCount = 0 };
        }
    }

    private async Task LoadMoreMessages()
    {
        if (_isLoadingMore || !_hasMoreMessages || _selectedChannel is null) return;

        _isLoadingMore = true;
        StateHasChanged();

        double previousHeight = 0;
        if (_messageArea is not null)
        {
            previousHeight = await _messageArea.GetScrollHeightAsync();
        }

        var older = await ChatService.GetMessagesAsync(_selectedChannel.Id, _skip, PageSize);
        _messages.InsertRange(0, older);
        _skip += older.Count;
        _hasMoreMessages = older.Count >= PageSize;
        _isLoadingMore = false;

        BuildThreadSummaries();
        StateHasChanged();

        // Restore scroll position so the view doesn't jump
        if (_messageArea is not null && previousHeight > 0)
        {
            await Task.Yield();
            await _messageArea.PreserveScrollAsync(previousHeight);
        }
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannel is null) return;

        var message = await ChatService.SendMessageAsync(_selectedChannel.Id, content, null);
        _messages.Add(message);
        StateHasChanged();

        if (_messageArea is not null)
        {
            await Task.Yield();
            await _messageArea.ScrollToBottomAsync();
        }
    }

    private async Task OpenThread(int messageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == messageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(messageId);
        _threadOpen = true;

        // Ensure thread summary reflects loaded data
        _threadSummaries[messageId] = new ThreadSummary(
            messageId,
            _threadReplies.Count,
            _threadReplies.Count > 0 ? _threadReplies[^1].SentAt : _threadRootMessage.SentAt);
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_selectedChannel is null || _threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            _selectedChannel.Id, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        _threadSummaries[_threadRootMessage.Id] = new ThreadSummary(
            _threadRootMessage.Id,
            _threadReplies.Count,
            reply.SentAt);
    }

    private async Task HandleReaction(ReactionRequest request)
    {
        await ChatService.AddReactionAsync(request.MessageId, request.Emoji);

        // Optimistic update
        var msgIndex = _messages.FindIndex(m => m.Id == request.MessageId);
        if (msgIndex >= 0)
        {
            var msg = _messages[msgIndex];
            var reactions = msg.Reactions.ToList();
            var existing = reactions.FindIndex(r => r.Emoji == request.Emoji);

            if (existing >= 0)
            {
                var r = reactions[existing];
                if (!r.Users.Contains("You"))
                {
                    reactions[existing] = r with { Users = [.. r.Users, "You"] };
                }
            }
            else
            {
                reactions.Add(new Reaction(request.Emoji, ["You"]));
            }

            _messages[msgIndex] = msg with { Reactions = reactions };
        }
    }

    private void BuildThreadSummaries()
    {
        _threadSummaries = _messages
            .Where(m => m.ReplyToId.HasValue)
            .GroupBy(m => m.ReplyToId!.Value)
            .ToDictionary(
                g => g.Key,
                g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)));
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    background: #1e1f22;
    color: #dbdee1;
    font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
}

